mapper.select:
SELECT m.sessionId, m.roleId, r.roleName, MAX(m.createTime) AS updateTime, (SELECT message FROM sys_message sm WHERE sm.sessionId = m.sessionId AND sm.sender = 'user' AND sm.state = '1' ORDER BY sm.createTime ASC LIMIT 1) AS title FROM sys_message m LEFT JOIN sys_role r ON m.roleId = r.roleId WHERE m.state = '1' AND m.sessionId IS NOT NULL AND m.sessionId != ''
AND m.userId = #{userId}
AND m.roleId = #{roleId}
AND m.source = #{source}
GROUP BY m.sessionId, m.roleId, r.roleName ORDER BY updateTime DESC
